app_conf:
# Redirection HTTP -> HTTPS
server {
    listen 80;
    server_name makopay.live api.makopay.live admin.makopay.live;
    return 301 https://$host$request_uri;
}
# API Backend
server {
    listen 443 ssl http2;
    server_name api.makopay.live;
    ssl_certificate /etc/nginx/ssl/cert.pem;
    ssl_certificate_key /etc/nginx/ssl/key.pem;
    location / {
        proxy_pass http://backend:3000;
        proxy_http_version 1.1;
        proxy_set_header Upgrade $http_upgrade;
        proxy_set_header Connection 'upgrade';
        proxy_set_header Host $host;
        proxy_cache_bypass $http_upgrade;
        proxy_set_header X-Real-IP $remote_addr;
    }
}
# Frontend (Finance Hub)
server {
    listen 443 ssl http2;
    server_name makopay.live www.makopay.live;
    ssl_certificate /etc/nginx/ssl/cert.pem;
    ssl_certificate_key /etc/nginx/ssl/key.pem;
    location / {
        proxy_pass http://frontend:80;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
    }
}

# Admin Dashboard
server {
    listen 443 ssl http2;
    server_name admin.makopay.live;
    ssl_certificate /etc/nginx/ssl/cert.pem;
    ssl_certificate_key /etc/nginx/ssl/key.pem;
    location / {
        proxy_pass http://admin:80;  # ✅ Corrigé : admin au lieu de frontend
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
    }
}

dartsia_conf:
server {
    listen 80;
    server_name api.dartsia.app;

    location / {
        proxy_pass http://tchedes-api:3000;
        proxy_http_version 1.1;
        proxy_set_header Upgrade $http_upgrade;
        proxy_set_header Connection 'upgrade';
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_cache_bypass $http_upgrade;
    }
}
